import { useState, useCallback } from "react";

/**
 * useRegistrationForm — manages all form state, errors, and step transitions
 */
export function useRegistrationForm() {
  const [step, setStep] = useState(1);
  const totalSteps = 3;

  const [fields, setFields] = useState({
    firstName: "",
    lastName: "",
    email: "",
    countryCode: "+91",
    mobile: "",
    dob: "",
    gender: "",
    password: "",
    confirmPassword: "",
    referral: "",
    termsAccepted: false,
  });

  const [errors, setErrors] = useState({});

  const updateField = useCallback((name, value) => {
    setFields((prev) => ({ ...prev, [name]: value }));
    // Clear error on change
    setErrors((prev) => {
      const next = { ...prev };
      delete next[name];
      return next;
    });
  }, []);

  const setFieldError = useCallback((name, message) => {
    setErrors((prev) => ({ ...prev, [name]: message }));
  }, []);

  const setMultipleErrors = useCallback((errorMap) => {
    setErrors((prev) => ({ ...prev, ...errorMap }));
  }, []);

  const clearError = useCallback((name) => {
    setErrors((prev) => {
      const next = { ...prev };
      delete next[name];
      return next;
    });
  }, []);

  const goToStep = useCallback((n) => {
    setStep(n);
  }, []);

  const nextStep = useCallback(() => {
    setStep((s) => Math.min(s + 1, totalSteps));
  }, [totalSteps]);

  const prevStep = useCallback(() => {
    setStep((s) => Math.max(s - 1, 1));
  }, []);

  return {
    step,
    totalSteps,
    fields,
    errors,
    updateField,
    setFieldError,
    setMultipleErrors,
    clearError,
    goToStep,
    nextStep,
    prevStep,
  };
}

/**
 * useOtp — manages OTP timer and state
 */
export function useOtp() {
  const [generatedOtp, setGeneratedOtp] = useState("");
  const [timerSeconds, setTimerSeconds] = useState(0);
  const [timerActive, setTimerActive] = useState(false);

  const startTimer = useCallback((seconds) => {
    setTimerSeconds(seconds);
    setTimerActive(true);
    const interval = setInterval(() => {
      setTimerSeconds((t) => {
        if (t <= 1) {
          clearInterval(interval);
          setTimerActive(false);
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  return { generatedOtp, setGeneratedOtp, timerSeconds, timerActive, startTimer };
}
